action.old_str:
%{
#include "lex.hpp"
/* 所有代码全部抽离出来，放到 lex.hpp 和 lex.cpp 里 */

using namespace lex;

#define ADDCOL() g.mColumn += yyleng;
#define COME(id) return come(id, yytext, yyleng, yylineno)
%}

%option 8bit warn noyywrap yylineno

D     [0-9]
L     [a-zA-Z_]
IS    ((u|U)|(u|U)?(l|L|ll|LL)|(l|L|ll|LL)(u|U))

%%

"int"       { ADDCOL(); COME(INT); }
"return"    { ADDCOL(); COME(RETURN); }

"("         { ADDCOL(); COME(L_PAREN); }
")"         { ADDCOL(); COME(R_PAREN); }
"["         { ADDCOL(); COME(L_SQUARE); }
"]"         { ADDCOL(); COME(R_SQUARE); }
"{"         { ADDCOL(); COME(L_BRACE); }
"}"         { ADDCOL(); COME(R_BRACE); }

"+"         { ADDCOL(); COME(PLUS); }

";"         { ADDCOL(); COME(SEMI); }
","         { ADDCOL(); COME(COMMA); }

"="         { ADDCOL(); COME(EQUAL); }

{L}({L}|{D})*         { ADDCOL(); COME(IDENTIFIER); }

L?\"(\\.|[^\\"\n])*\" { ADDCOL(); COME(STRING_LITERAL); }

0[0-7]*{IS}?          { ADDCOL(); COME(CONSTANT); }
[1-9]{D}*{IS}?        { ADDCOL(); COME(CONSTANT); }

^#[^\n]*              { return ~YYEOF; } /* 预处理信息处理，可以从预处理信息中获得文件名以及行号 */

[ \t\v\n\f]           { return ~YYEOF; } /* 需要处理行号和列号信息 */

<<EOF>>     { ADDCOL(); COME(YYEOF); }

%%

/* about symbols avaliable (yytext, yyleng etc.) in the context of Flex:
 * https://ftp.gnu.org/old-gnu/Manuals/flex-2.5.4/html_node/flex_14.html
 * https://ftp.gnu.org/old-gnu/Manuals/flex-2.5.4/html_node/flex_15.html
*/

action.new_str:
%{
#include "lex.hpp"
/* 所有代码全部抽离出来，放到 lex.hpp 和 lex.cpp 里 */

using namespace lex;

#define ADDCOL() g.mColumn += yyleng;
#define COME(id) return come(id, yytext, yyleng, yylineno)
%}

%option 8bit warn noyywrap yylineno

D     [0-9]
L     [a-zA-Z_]
H     [a-fA-F0-9]
E     ([Ee][+-]?{D}+)
P     ([Pp][+-]?{D}+)
FS    (f|F|l|L)
IS    ((u|U)|(u|U)?(l|L|ll|LL)|(l|L|ll|LL)(u|U))

%%

"void"      { ADDCOL(); COME(VOID); }
"int"       { ADDCOL(); COME(INT); }
"const"     { ADDCOL(); COME(CONST); }
"if"        { ADDCOL(); COME(IF); }
"else"      { ADDCOL(); COME(ELSE); }
"while"     { ADDCOL(); COME(WHILE); }
"break"     { ADDCOL(); COME(BREAK); }
"continue"  { ADDCOL(); COME(CONTINUE); }
"return"    { ADDCOL(); COME(RETURN); }

"("         { ADDCOL(); COME(L_PAREN); }
")"         { ADDCOL(); COME(R_PAREN); }
"["         { ADDCOL(); COME(L_SQUARE); }
"]"         { ADDCOL(); COME(R_SQUARE); }
"{"         { ADDCOL(); COME(L_BRACE); }
"}"         { ADDCOL(); COME(R_BRACE); }

";"         { ADDCOL(); COME(SEMI); }
","         { ADDCOL(); COME(COMMA); }

"..."       { ADDCOL(); COME(ELLIPSIS); }
"->"        { ADDCOL(); COME(ARROW); }
"<<"        { ADDCOL(); COME(LSHIFT); }
">>"        { ADDCOL(); COME(RSHIFT); }
"=="        { ADDCOL(); COME(EQUALEQUAL); }
"!="        { ADDCOL(); COME(EXCLAIMEQUAL); }
"&&"        { ADDCOL(); COME(AMPAMP); }
"||"        { ADDCOL(); COME(PIPEPIPE); }
"<="        { ADDCOL(); COME(LESSEQUAL); }
">="        { ADDCOL(); COME(GREATEREQUAL); }
"++"        { ADDCOL(); COME(PLUSPLUS); }
"--"        { ADDCOL(); COME(MINUSMINUS); }
"+="        { ADDCOL(); COME(PLUSEQUAL); }
"-="        { ADDCOL(); COME(MINUSEQUAL); }
"*="        { ADDCOL(); COME(STAREQUAL); }
"/="        { ADDCOL(); COME(SLASHEQUAL); }
"%="        { ADDCOL(); COME(PERCENTEQUAL); }
"&="        { ADDCOL(); COME(AMPEQUAL); }
"|="        { ADDCOL(); COME(PIPEEQUAL); }
"^="        { ADDCOL(); COME(CARETEQUAL); }
"<<="       { ADDCOL(); COME(LSHIFTEQUAL); }
">>="       { ADDCOL(); COME(RSHIFTEQUAL); }

"+"         { ADDCOL(); COME(PLUS); }
"-"         { ADDCOL(); COME(MINUS); }
"*"         { ADDCOL(); COME(STAR); }
"/"         { ADDCOL(); COME(SLASH); }
"%"         { ADDCOL(); COME(PERCENT); }
"<"         { ADDCOL(); COME(LESS); }
">"         { ADDCOL(); COME(GREATER); }
"="         { ADDCOL(); COME(EQUAL); }
"!"         { ADDCOL(); COME(EXCLAIM); }
"&"         { ADDCOL(); COME(AMP); }
"|"         { ADDCOL(); COME(PIPE); }
"^"         { ADDCOL(); COME(CARET); }
"~"         { ADDCOL(); COME(TILDE); }
"?"         { ADDCOL(); COME(QUESTION); }
":"         { ADDCOL(); COME(COLON); }
"."         { ADDCOL(); COME(DOT); }

{L}({L}|{D})*         { ADDCOL(); COME(IDENTIFIER); }

L?\"(\\.|[^\\"\n])*\" { ADDCOL(); COME(STRING_LITERAL); }

0[xX]{H}+{IS}?        { ADDCOL(); COME(CONSTANT); }
0[0-7]*{IS}?          { ADDCOL(); COME(CONSTANT); }
[1-9]{D}*{IS}?        { ADDCOL(); COME(CONSTANT); }

^#[^\n]*              { handle_line_marker(yytext, yyleng); return ~YYEOF; }

"//"[^\n]*            { return ~YYEOF; }
"/*"([^*]|\*+[^*/])*\*+"/" { return ~YYEOF; }

[ \t]+                { g.mLeadingSpace = true; g.mColumn += yyleng; return ~YYEOF; }
\n                    { g.mStartOfLine = true; g.mLeadingSpace = false; g.mColumn = 1; return ~YYEOF; }
\r                    { return ~YYEOF; }

<<EOF>>     { ADDCOL(); COME(YYEOF); }

%%

